const u = $json || {};

const msg = u.message || u.edited_message || u.channel_post || u.edited_channel_post || null;
const cq = u.callback_query || null;
const isCallback = !!cq;
const sourceMsg = (cq && cq.message) ? cq.message : msg;

const telegramIdRaw =
  (cq && cq.from && cq.from.id) ||
  (msg && msg.from && msg.from.id) ||
  null;

const chatIdRaw =
  (sourceMsg && sourceMsg.chat && sourceMsg.chat.id) ||
  null;

const telegram_id = (telegramIdRaw !== null && telegramIdRaw !== undefined) ? Number(telegramIdRaw) : null;
const chat_id = (chatIdRaw !== null && chatIdRaw !== undefined) ? Number(chatIdRaw) : null;

const update_id = (u.update_id !== undefined && u.update_id !== null) ? Number(u.update_id) : null;

const message_id =
  (sourceMsg && sourceMsg.message_id !== undefined) ? Number(sourceMsg.message_id) :
  null;

const rawText = isCallback
  ? (cq.data || '')
  : ((sourceMsg && (sourceMsg.text || sourceMsg.caption)) || '');

const text = String(rawText).trim();
const callback_data = isCallback ? String(cq.data || '') : '';
const callback_query_id = (isCallback && cq.id) ? String(cq.id) : '';

const photos = (sourceMsg && sourceMsg.photo) ? sourceMsg.photo : [];

const has_photo = Array.isArray(photos) && photos.length > 0;
const photo_file_id = has_photo ? String(photos[photos.length - 1].file_id || '') : '';

return {
  json: {
    telegram_id,
    chat_id,
    text,
    callback_data,
    is_callback: isCallback,
    has_photo,
    photo_file_id,
    callback_query_id,
    update_id,
    message_id,
    update_type: isCallback ? 'callback' : (u.edited_message ? 'edited_message' : (u.channel_post || u.edited_channel_post ? 'channel_post' : 'message')),
  }
};

const session = $input.first().json || {};
const n = $node["Normalize"].json || {};

// helper: берём новое значение только если оно реально заполнено
const pickNonEmpty = (a, b) => {
  if (a === null || a === undefined) return b;
  if (typeof a === 'string' && a.trim() === '') return b;
  return a;
};

const merged = {
  ...session,

  telegram_id: pickNonEmpty(n.telegram_id, session.telegram_id),
  chat_id: pickNonEmpty(n.chat_id, session.chat_id),

  text: (n.text ?? '').toString(),
  callback_data: (n.callback_data ?? '').toString(),
  is_callback: !!n.is_callback,

  // Важно: НЕ затираем сохранённое фото пустотой
  has_photo: (n.has_photo === true) ? true : (session.has_photo === true),

  photo_file_id: pickNonEmpty(n.photo_file_id, session.photo_file_id),
};

return [{ json: merged }];

const code = ($json.text || '').trim().toUpperCase();

const map = {
  CAT_APPAREL: 'Одежда',
  CAT_CLOTHES: 'Одежда',
  CAT_SHOES: 'Обувь',
  CAT_BEAUTY: 'Красота и уход',
  CAT_HOME: 'Дом и кухня',
  CAT_ELECTRONICS: 'Электроника',
  CAT_KIDS: 'Детские товары',
  CAT_SPORT: 'Спорт и отдых',
  CAT_AUTO: 'Авто-товары',
  'ОДЕЖДА': 'Одежда',
  'ОБУВЬ': 'Обувь',
  'КРАСОТА': 'Красота и уход',
  'ДОМ И КУХНЯ': 'Дом и кухня',
  'ЭЛЕКТРОНИКА': 'Электроника',
  'ДЕТЯМ': 'Детские товары',
  'СПОРТ': 'Спорт и отдых',
  'АВТО': 'Авто-товары',
};

return [{
  json: {
    ...$json,
    category_mapped: map[code] || 'Другое',
  }
}];

const j = $json;
const content = j?.choices?.[0]?.message?.content ?? j?.choices?.[0]?.text ?? '';
const raw_text = (typeof content === 'string' ? content : JSON.stringify(content)).trim();

let parsed = null;
try { parsed = JSON.parse(raw_text); } catch (e) {
  const m = raw_text.match(/\{[\s\S]*\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch (_) {} }
}

const fallback = {
  card: { title: (j.title || 'Товар').toString(), short_description: 'Недостаточно данных для финальной карточки. Уточните параметры товара.', benefits: [], specs: [], keywords: [] },
  marketing: { segments: [], usp_line: '', cover_headlines: [], slide_blocks: [] },
  service: { notes: [], warnings: ['Не удалось собрать валидный ответ модели. Попробуйте другое фото или добавьте уточнения.'] }
};

if (!parsed || typeof parsed !== 'object') parsed = fallback;
if (!parsed.card || typeof parsed.card !== 'object') parsed.card = fallback.card;
if (!parsed.marketing || typeof parsed.marketing !== 'object') parsed.marketing = fallback.marketing;
if (!parsed.service || typeof parsed.service !== 'object') parsed.service = fallback.service;

parsed.card.benefits = Array.isArray(parsed.card.benefits) ? parsed.card.benefits : [];
parsed.card.specs = Array.isArray(parsed.card.specs) ? parsed.card.specs : [];
parsed.card.keywords = Array.isArray(parsed.card.keywords) ? parsed.card.keywords : [];
parsed.marketing.segments = Array.isArray(parsed.marketing.segments) ? parsed.marketing.segments : [];
parsed.marketing.cover_headlines = Array.isArray(parsed.marketing.cover_headlines) ? parsed.marketing.cover_headlines : [];
parsed.marketing.slide_blocks = Array.isArray(parsed.marketing.slide_blocks) ? parsed.marketing.slide_blocks : [];
parsed.service.notes = Array.isArray(parsed.service.notes) ? parsed.service.notes : [];
parsed.service.warnings = Array.isArray(parsed.service.warnings) ? parsed.service.warnings : [];

return { json: { ...j, final_json: parsed, card: parsed.card, marketing: parsed.marketing, service: parsed.service, raw_text } };

const j = $json;
const normalized = j.normalized || {};
const b64 = (j.image_base64_clean || '').toString().trim();

const inputData = {
  marketplace: (j.marketplace || '').toString().trim(),
  category: (j.category || '').toString().trim(),
  title: (j.title || '').toString().trim(),
  benefits: (j.benefits || '').toString().trim(),
  clarifications_answers: (j.clarifications_answers || '').toString().trim(),
  facts: Array.isArray(normalized.facts) ? normalized.facts : [],
  unknowns: Array.isArray(normalized.unknowns) ? normalized.unknowns : [],
};

const system = `
Ты senior e-commerce copywriter и market-analyst для WB/Ozon.
Верни строго JSON структуры:
{
  "card": {"title":"","short_description":"","benefits":[],"specs":[{"key":"","value":""}],"keywords":[]},
  "marketing": {"segments":[{"name":"","pain":"","promise":""}],"usp_line":"","cover_headlines":[],"slide_blocks":[]},
  "service": {"notes":[],"warnings":[]}
}

Правила:
- Не выдумывай факты и характеристики. Если параметр неизвестен, пиши "не указано" или добавляй предупреждение.
- Строго опирайся на входные данные и фото товара.
- Проведи рыночное позиционирование по категории и маркетплейсу (паттерны конкурентов), но без выдуманных техпараметров.
- Русский язык, деловой и убедительный стиль.
- Никаких эмодзи.
- Для cover_headlines дай 3-5 вариантов, для slide_blocks 8-10 блоков с продающей логикой.
`;

const body = {
  model: $env.OPENROUTER_TEXT_MODEL || 'openai/gpt-4o-mini',
  temperature: 0.35,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: system.trim() },
    {
      role: 'user',
      content: [
        { type: 'text', text: `Входные данные:
${JSON.stringify(inputData, null, 2)}` },
        ...(b64 ? [{ type: 'image_url', image_url: { url: `data:image/jpeg;base64,${b64}` } }] : []),
      ],
    },
  ],
};

return { json: { ...j, openrouter_body: body } };

// mode: runOnceForEachItem
const j = $json;
const b64 = ((j.image_base64 || '') + '').toString();
const clean = b64.replace(/[^A-Za-z0-9+/=]/g, '');

if (!clean) {
  return { json: { ...j, image_base64_clean: '', image_base64_len: 0,
    _sanitize_error: 'Не удалось прочитать изображение. Пожалуйста, отправьте другое фото.' } };
}
if (clean.length < 1000) {
  return { json: { ...j, image_base64_clean: '', image_base64_len: 0,
    _sanitize_error: 'Изображение слишком маленькое или повреждено. Пожалуйста, отправьте другое фото.' } };
}
const maxLen = 2_500_000;
if (clean.length > maxLen) {
  return { json: { ...j, image_base64_clean: '', image_base64_len: 0,
    _sanitize_error: 'Фото слишком большое. Пожалуйста, выберите фото меньшего размера (до 5 МБ) и отправьте снова.' } };
}
return { json: { ...j, image_base64_clean: clean, image_base64_len: clean.length, _sanitize_error: '' } };

const j = $json;
const raw = (j.benefits || "").toString();

function norm(s) { return (s || "").toString().trim(); }

const lines = raw.split(/\r?\n/).map(l => l.trim()).filter(Boolean);

// 1) пары key/value: "ключ: значение"
const specs = [];
const used = new Set();

for (let i = 0; i < lines.length; i++) {
  const line = lines[i];

  const m = line.match(/^(.{2,50}?)[\:\-]\s*(.+)$/i);
  if (m) {
    specs.push({ key: norm(m[1]), value: norm(m[2]), unit: "", source: "user", confidence: 0.9 });
    used.add(i);
    continue;
  }

  // 2) "ключ" затем "значение" на следующей строке
  if (i < lines.length - 1) {
    const next = lines[i + 1];
    const looksKey = line.length <= 50 && !/[0-9]/.test(line);
    const looksValue = next.length <= 60;
    if (looksKey && looksValue) {
      specs.push({ key: norm(line), value: norm(next), unit: "", source: "user", confidence: 0.8 });
      used.add(i); used.add(i + 1);
      i++;
    }
  }
}

const leftover_lines = lines.filter((_, idx) => !used.has(idx));
const leftover_text = leftover_lines.join("\n");

return {
  json: {
    ...j,
    parsed_deterministic: {
      specs,
      leftover_text,
      leftover_len: leftover_text.length
    }
  }
};

const j = $json;
const marketplace = (j.marketplace || '').toString().trim();
const category = (j.category || '').toString().trim();
const title = (j.title || '').toString().trim();
const benefits = (j.benefits || '').toString().trim();
const clarifications_answers = (j.clarifications_answers || '').toString().trim();
const imageBase64 = (j.image_base64_clean || '').toString().trim();

const system = `
Ты анализируешь карточку товара для WB/Ozon. Возвращай только факты из входных данных и фото.
Нельзя выдумывать характеристики, материалы, объёмы, мощность, комплектацию и любые числовые параметры.
Если данных не хватает для безопасной генерации карточки, ставь need_clarifications=true и задай до 5 коротких вопросов.
Верни строго JSON-объект.
`;

const userData = {
  marketplace, category, title, benefits, clarifications_answers,
  image_present: !!imageBase64
};

const prompt = `Верни JSON структуры:
{
  "need_clarifications": boolean,
  "clarifications_questions": string[],
  "facts": string[],
  "unknowns": string[]
}

Данные:
${JSON.stringify(userData, null, 2)}`;

const body = {
  model: $env.OPENROUTER_TEXT_MODEL || 'openai/gpt-4o-mini',
  temperature: 0.2,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: system.trim() },
    {
      role: 'user',
      content: [
        { type: 'text', text: prompt },
        ...(imageBase64 ? [{ type: 'image_url', image_url: { url: `data:image/jpeg;base64,${imageBase64}` } }] : []),
      ],
    },
  ],
};

return { json: { ...j, openrouter_body: body } };

const j = $json;
const content = j?.choices?.[0]?.message?.content ?? '';
const raw = (typeof content === 'string' ? content : JSON.stringify(content)).trim();

const safe = { need_clarifications: true, clarifications_questions: ['Уточни ключевые параметры товара: размер, материал, комплектацию и важные функции.'], facts: [], unknowns: ['Недостаточно данных для точной карточки.'] };

let parsed = null;
try { parsed = JSON.parse(raw); } catch (e) {
  const m = raw.match(/\{[\s\S]*\}/);
  if (m) { try { parsed = JSON.parse(m[0]); } catch (_) {} }
}
if (!parsed || typeof parsed !== 'object') parsed = safe;

const normalized = {
  need_clarifications: !!parsed.need_clarifications,
  clarifications_questions: Array.isArray(parsed.clarifications_questions) ? parsed.clarifications_questions.map(x => String(x).trim()).filter(Boolean) : [],
  facts: Array.isArray(parsed.facts) ? parsed.facts.map(x => String(x).trim()).filter(Boolean) : [],
  unknowns: Array.isArray(parsed.unknowns) ? parsed.unknowns.map(x => String(x).trim()).filter(Boolean) : [],
};
if (!normalized.clarifications_questions.length && normalized.need_clarifications) {
  normalized.clarifications_questions = safe.clarifications_questions;
}

return { json: { ...j, normalized, clarifications_questions: normalized.clarifications_questions } };

const j = $json;

let qs =
  j.clarifications_questions ??
  j.strategy?.clarifications_questions ??
  [];

let listText = "";

if (Array.isArray(qs)) {
  listText = qs
    .map((q, i) => `${i + 1}. ${String(q).trim()}`)
    .join("\n");
} else {
  listText = String(qs || "").trim();
}

// если модель/предыдущие шаги уже добавили заголовок/инструкцию — чистим
listText = listText
  .replace(/^\s*Уточняющие вопросы:\s*/gi, "")
  .replace(/\n\s*Уточняющие вопросы:\s*/gi, "\n")
  .replace(/\n?\s*Ответь одним сообщением[\s\S]*$/i, "")
  .trim();

const text = (
  "Уточняющие вопросы:\n" +
  (listText || "Уточни, пожалуйста, ключевые характеристики товара (размер/материал/комплектацию/важные функции).") +
  "\n\nОтветь одним сообщением, можно списком."
).trim();

return { json: { ...j, text } };

const esc = (s) => String(s ?? '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const j = $json || {};
const card = j.card || {};
const marketing = j.marketing || {};
const service = j.service || {};
const normalized = j.normalized || {};

const uniq = (arr=[]) => [...new Set(arr.map(x=>String(x||'').trim()).filter(Boolean))];

let keywords = Array.isArray(card.keywords) ? card.keywords : [];
keywords = uniq(keywords);
if (keywords.length < 12) {
  const seed = [j.title, j.category, j.marketplace, ...(Array.isArray(card.benefits)?card.benefits:[])];
  const words = uniq(seed.join(' ').toLowerCase().replace(/[^a-zа-я0-9\s-]/gi,' ').split(/\s+/).filter(w=>w.length>2));
  for (const w of words) {
    if (keywords.length >= 18) break;
    if (!keywords.includes(w)) keywords.push(w);
  }
}
if (keywords.length < 12) {
  keywords = uniq([...keywords, 'купить', 'цена', 'доставка', 'оригинал', 'для дома', 'для работы', 'для подарка', 'практичный', 'качественный', 'современный', 'популярный', 'выгодно']).slice(0, 18);
}

const cover = uniq(Array.isArray(marketing.cover_headlines) ? marketing.cover_headlines : []).slice(0,7);
const rawSlides = Array.isArray(marketing.slide_blocks) ? marketing.slide_blocks : [];
const slides = uniq(rawSlides.map((s) => {
  if (typeof s === 'string') return s;
  if (s && typeof s === 'object') {
    const title = String(s.title || s.name || '').trim();
    const text = String(s.text || s.description || s.copy || '').trim();
    const bullets = Array.isArray(s.bullets) ? s.bullets.map((b)=>String(b||'').trim()).filter(Boolean) : [];
    const base = [title, text].filter(Boolean).join(': ');
    if (bullets.length) return [base || 'Блок', ...bullets.map((b)=>`• ${b}`)].join(' | ');
    return base || '';
  }
  return String(s || '').trim();
})).slice(0,10);
const benefits = uniq(Array.isArray(card.benefits) ? card.benefits : []).slice(0,7);
const sourceFacts = [j.title, j.benefits, j.clarifications_answers, ...(Array.isArray(normalized.facts) ? normalized.facts : [])].join(' ').toLowerCase();
const rawSpecs = Array.isArray(card.specs) ? card.specs : [];
const specs = rawSpecs.filter((s) => {
  const key = String((s && s.key) || '').trim().toLowerCase();
  const val = String((s && s.value) || '').trim().toLowerCase();
  if (!key && !val) return false;
  if (val === 'не указано' || key === 'не указано') return true;
  if (!sourceFacts) return false;
  const probe = `${key} ${val}`.trim();
  if (!probe) return false;
  return sourceFacts.includes(val) || sourceFacts.includes(key) || sourceFacts.includes(probe);
});

const lines = [];
lines.push('<b>SEO-название под поиск</b>');
lines.push(esc(card.title || j.title || 'не указано'));

lines.push('');
lines.push('<b>Понятные буллеты и преимущества</b>');
if (benefits.length) for (const b of benefits) lines.push(`• ${esc(b)}`);
else lines.push('• не указано');

lines.push('');
lines.push('<b>Описание без воды</b>');
lines.push(esc(card.short_description || 'не указано'));

lines.push('');
lines.push('<b>Характеристики</b>');
if (specs.length) {
  for (const s of specs.slice(0,12)) lines.push(`• ${esc(s?.key || 'Параметр')}: ${esc(s?.value || 'не указано')}`);
} else lines.push('• не указано');

lines.push('');
lines.push('<b>Ключевые слова</b>');
lines.push(esc(keywords.slice(0,30).join(', ')));

lines.push('');
lines.push('<b>Идеи для обложки и слайдов</b>');
lines.push('<i>Обложка: варианты заголовков</i>');
if (cover.length) for (const h of cover) lines.push(`• ${esc(h)}`);
else lines.push('• Акцент на главной выгоде и понятном результате для покупателя.');

lines.push('');
lines.push('<i>План слайдов (текст + визуал)</i>');
if (slides.length) for (const s of slides) lines.push(`• ${esc(s)}`);
else {
  const fallbackSlides = [
    'Слайд 1: оффер и ключевая выгода; визуал — товар крупным планом на чистом фоне.',
    'Слайд 2: 3 главных преимущества; визуал — иконки и короткие подписи.',
    'Слайд 3: сценарий использования; визуал — контекст применения.',
    'Слайд 4: характеристики; визуал — структурированная таблица.',
    'Слайд 5: комплектация/детали; визуал — выноски на фото.',
    'Слайд 6: сравнение с альтернативами; визуал — нейтральные колонки.',
    'Слайд 7: качество и материалы; визуал — фактура/крупные фрагменты.',
    'Слайд 8: финальный CTA; визуал — товар + короткий призыв.'
  ];
  for (const s of fallbackSlides) lines.push(`• ${esc(s)}`);
}

const warnings = uniq([
  ...(Array.isArray(service.warnings) ? service.warnings : []),
  ...(Array.isArray(normalized.unknowns) ? normalized.unknowns : []),
]);
if (warnings.length) {
  lines.push('');
  lines.push('<b>Что важно уточнить</b>');
  for (const w of warnings.slice(0,10)) lines.push(`• ${esc(w)}`);
}

const text = lines.join('\n').trim() || 'Не удалось собрать карточку. Попробуйте другое фото или добавьте уточнения.';
const limit = 3900;
const chunks = [];
let remaining = text;
while (remaining.length > limit) {
  let cut = remaining.lastIndexOf('\n', limit);
  if (cut < 1200) cut = limit;
  chunks.push(remaining.slice(0, cut).trim());
  remaining = remaining.slice(cut).trim();
}
if (remaining) chunks.push(remaining);
return { json: { ...j, result_text_formatted: text, parts: chunks.length ? chunks : [text] } };

// mode: runOnceForAllItems
const j = $input.first().json || {};
const pick = (...vals) => { for (const v of vals) { if (v !== undefined && v !== null && `${v}`.trim() !== '') return v; } return null; };
const norm = ($node['Normalize'] && $node['Normalize'].json) ? $node['Normalize'].json : {};
const sess = ($node['Session: Pick'] && $node['Session: Pick'].json) ? $node['Session: Pick'].json : {};

const chat_id = Number(pick(j.chat_id, sess.chat_id, norm.chat_id) || 0);
const title = (pick(j.title, sess.title) || 'товар').toString();
const category = (pick(j.category, sess.category) || 'категория').toString();
const marketplace = (pick(j.marketplace, sess.marketplace) || 'маркетплейс').toString();
const benefits = (pick(j.benefits, sess.benefits) || '').toString();
const render_mode = ((j.render_mode || 'TEXT') + '').trim().toUpperCase() === 'DRAW' ? 'DRAW' : 'TEXT';

const variants = [
  {
    style: 'Минимализм Premium',
    palette: 'Белый #FFFFFF · Тёмно-синий #1A237E · Акцент золотой #FFD700',
    background: 'Студийный белый с мягкими тенями',
    layout: 'Товар по центру 70%, 3 буллета снизу в карточках, типографика Montserrat Bold',
    typography: 'Заголовок: Montserrat Bold 72px, цвет #1A237E\nПодписи: Medium 28px\nАкценты: #FFD700',
    composition: 'Центральная ось, симметрия, product hero, safe zone 8%',
    image_prompt: `ultra-premium minimalist product card, ${title}, white studio background, soft shadows, dark navy blue typography, golden accent lines, Montserrat font style, clean symmetric composition, luxury e-commerce photography, 4k quality, no watermarks, professional lighting`
  },
  {
    style: 'Контраст Dark',
